const jwt = require('jsonwebtoken');
const User = require('../models/User');

// JWT密钥
const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key';
const JWT_REFRESH_SECRET = process.env.JWT_REFRESH_SECRET || 'your-refresh-secret-key';

// 生成访问令牌
const generateAccessToken = (user) => {
  return jwt.sign(
    { 
      id: user.id, 
      username: user.username,
      email: user.email,
      role: user.role
    },
    JWT_SECRET,
    { expiresIn: '1h' } // 1小时
  );
};

// 生成刷新令牌
const generateRefreshToken = (user) => {
  return jwt.sign(
    { 
      id: user.id,
      type: 'refresh'
    },
    JWT_REFRESH_SECRET,
    { expiresIn: '7d' } // 7天
  );
};

// 验证访问令牌
const verifyAccessToken = (token) => {
  try {
    return jwt.verify(token, JWT_SECRET);
  } catch (error) {
    return null;
  }
};

// 验证刷新令牌
const verifyRefreshToken = (token) => {
  try {
    return jwt.verify(token, JWT_REFRESH_SECRET);
  } catch (error) {
    return null;
  }
};

// 认证中间件（支持自动续期）
const authenticateToken = async (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer TOKEN
  const refreshToken = req.headers['x-refresh-token']; // 刷新令牌

  if (!token) {
    return res.status(401).json({ error: '访问令牌缺失' });
  }

  let decoded = verifyAccessToken(token);
  
  // 如果访问令牌过期且有刷新令牌，尝试自动续期
  if (!decoded && refreshToken) {
    try {
      const refreshDecoded = verifyRefreshToken(refreshToken);
      if (refreshDecoded && refreshDecoded.id) {
        // 验证刷新令牌有效，生成新的访问令牌
        const user = await User.findById(refreshDecoded.id);
        if (user) {
          const newAccessToken = generateAccessToken(user);
          
          // 在响应头中返回新的访问令牌
          res.setHeader('X-New-Access-Token', newAccessToken);
          res.setHeader('X-Token-Refreshed', 'true');
          
          // 继续处理请求
          user.role = user.role || 'user';
          req.user = user;
          return next();
        }
      }
    } catch (error) {
      console.error('刷新令牌验证失败:', error);
    }
  }

  if (!decoded) {
    return res.status(403).json({ error: '访问令牌无效或已过期' });
  }

  try {
    // 获取用户信息
    const user = await User.findById(decoded.id);
    if (!user) {
      return res.status(403).json({ error: '用户不存在' });
    }

    // 确保role信息从JWT token中获取
    user.role = decoded.role || user.role;
    req.user = user;
    next();
  } catch (error) {
    console.error('认证中间件错误:', error);
    return res.status(500).json({ error: '服务器内部错误' });
  }
};

// 可选认证中间件（不强制要求认证）
const optionalAuth = async (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (token) {
    const decoded = verifyAccessToken(token);
    if (decoded) {
      try {
        const user = await User.findById(decoded.id);
        if (user) {
          req.user = user;
        }
      } catch (error) {
        console.error('可选认证错误:', error);
      }
    }
  }

  // 如果没有认证用户，检查是否为游客模式
  if (!req.user) {
    // 从请求体中获取游客ID
    const guestId = req.body.userId || req.query.userId;
    if (guestId && guestId.startsWith('guest_')) {
      req.user = {
        id: guestId,
        username: '游客',
        role: 'guest',
        isGuest: true
      };
    }
  }

  next();
};

// 管理员权限中间件
const requireAdmin = (req, res, next) => {
  if (!req.user) {
    return res.status(401).json({ error: '需要认证' });
  }

  if (req.user.role !== 'admin') {
    return res.status(403).json({ error: '需要管理员权限' });
  }

  next();
};

module.exports = {
  generateAccessToken,
  generateRefreshToken,
  verifyAccessToken,
  verifyRefreshToken,
  authenticateToken,
  optionalAuth,
  requireAdmin,
  JWT_SECRET,
  JWT_REFRESH_SECRET
};
